const DEFAULT_TAKES = 3;
const MAX_TAKES = 5;
const MIN_DURATION = 0.5;
const MAX_DURATION = 30;
const DEFAULT_INFLUENCE = 0.3;
const INFLUENCE_STEP = 0.1;
const PARENT_FOLDER_ID = 'PASTE_YOUR_SFX_OUTPUT_FOLDER_ID_HERE';

const clamp = (n, lo, hi) => Math.max(lo, Math.min(hi, n));
const form = $input.first().json;

const brief = String(form['Description'] || '').trim();

let takes = Math.round(Number(form['Number of takes']) || DEFAULT_TAKES);
takes = clamp(takes, 1, MAX_TAKES);

let duration = null;
const rawDuration = form['Duration seconds'];
if (rawDuration !== '' && rawDuration != null && !isNaN(Number(rawDuration))) {
  duration = clamp(Number(rawDuration), MIN_DURATION, MAX_DURATION);
}

let baseInfluence = DEFAULT_INFLUENCE;
const rawInfluence = form['Prompt influence'];
if (rawInfluence !== '' && rawInfluence != null && !isNaN(Number(rawInfluence))) {
  baseInfluence = clamp(Number(rawInfluence), 0, 1);
}

const slug = brief.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 40) || 'sound-effect';
const now = new Date();
const pad = (x) => String(x).padStart(2, '0');
const stamp = now.getFullYear() + pad(now.getMonth() + 1) + pad(now.getDate()) + '-' + pad(now.getHours()) + pad(now.getMinutes()) + pad(now.getSeconds());
const folderName = slug + '-' + stamp;

const list = [];
for (let i = 0; i < takes; i++) {
  const influence = clamp(Number((baseInfluence + i * INFLUENCE_STEP).toFixed(3)), 0, 1);
  list.push({ takeNumber: i + 1, prompt: brief, duration: duration, prompt_influence: influence });
}

return [{ json: { brief: brief, totalTakes: takes, duration: duration, baseInfluence: baseInfluence, folderName: folderName, parentFolderId: PARENT_FOLDER_ID, takes: list } }];

const plan = $('Plan Takes and Folder').first().json;
const takes = Array.isArray(plan.takes) ? plan.takes : [];

return takes.map((t) => {
  const body = { text: t.prompt, prompt_influence: t.prompt_influence };
  if (t.duration != null) body.duration_seconds = t.duration;
  return {
    json: {
      takeNumber: t.takeNumber,
      totalTakes: plan.totalTakes,
      prompt: t.prompt,
      prompt_influence: t.prompt_influence,
      duration: t.duration,
      bodyJson: JSON.stringify(body),
    },
    pairedItem: { item: 0 },
  };
});

const file = $json;
const takeNumber = $('Build Take Requests').item.json.takeNumber;
const id = file.id || '';
const link = file.webViewLink || (id ? ('https://drive.google.com/file/d/' + id + '/view') : '');
return {
  json: {
    takeNumber: takeNumber,
    status: 'ok',
    fileName: file.name || ('take-' + takeNumber + '.mp3'),
    link: link,
  },
};

let takeNumber = null;
try { takeNumber = $('Build Take Requests').item.json.takeNumber; } catch (e) {}
if (takeNumber == null) takeNumber = ($json.takeNumber != null ? $json.takeNumber : null);
const err = $json.error;
const message = (err && (err.message || err.description)) || (typeof err === 'string' ? err : '') || 'Generation or upload failed';
return {
  json: {
    takeNumber: takeNumber,
    status: 'failed',
    fileName: '',
    link: '',
    error: String(message),
  },
};

const rows = $input.all().map((i) => i.json).filter(Boolean);
rows.sort((a, b) => (a.takeNumber || 0) - (b.takeNumber || 0));

const plan = $('Plan Takes and Folder').first().json;
const brief = plan.brief || '';
const total = (plan.totalTakes != null ? plan.totalTakes : rows.length);
const folderId = $('Create Take Folder in Drive').first().json.id || '';
const folderUrl = folderId ? ('https://drive.google.com/drive/folders/' + folderId) : '';

const okRows = rows.filter((r) => r.status === 'ok');
const failedRows = rows.filter((r) => r.status !== 'ok');
const missing = Math.max(0, total - okRows.length - failedRows.length);

const esc = (s) => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const listItems = rows.map((r) => {
  if (r.status === 'ok') {
    return '<li>Take ' + esc(r.takeNumber) + ': <a href="' + esc(r.link) + '" target="_blank" rel="noopener">' + esc(r.fileName || ('take-' + r.takeNumber + '.mp3')) + '</a></li>';
  }
  return '<li>Take ' + esc(r.takeNumber) + ': failed (' + esc(r.error || 'unknown error') + ')</li>';
}).join('');

const folderLine = folderUrl
  ? '<p><strong>Folder:</strong> <a href="' + esc(folderUrl) + '" target="_blank" rel="noopener">open the variation pack in Google Drive</a></p>'
  : '<p>The Drive folder link is unavailable.</p>';

let countLine = okRows.length + ' of ' + total + ' takes generated';
if (failedRows.length) countLine += ', ' + failedRows.length + ' failed';
if (missing) countLine += ', ' + missing + ' did not report back';
countLine += '.';

const html = '<div style="font-family:system-ui,Segoe UI,Arial,sans-serif;max-width:640px;line-height:1.55;">' +
  '<h2>Your sound effect variation pack</h2>' +
  '<p><strong>Brief:</strong> ' + esc(brief) + '</p>' +
  '<p>' + countLine + '</p>' +
  folderLine +
  '<ul>' + listItems + '</ul>' +
  '</div>';

return [{ json: { html: html, folderUrl: folderUrl, okCount: okRows.length, failedCount: failedRows.length, missingCount: missing, total: total, results: rows } }];
